'use client'

import { useState, useMemo } from 'react'
import { DoctorCard } from '@/components/doctors/doctor-card'
import { DoctorFilter } from '@/components/doctors/doctor-filter'
import { doctors } from '@/lib/mock-data'

export default function DoctorsPage() {
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedSpecialty, setSelectedSpecialty] = useState('all')
  const [sortBy, setSortBy] = useState('default')

  const filteredDoctors = useMemo(() => {
    let result = [...doctors]

    // Filter by search query
    if (searchQuery) {
      const query = searchQuery.toLowerCase()
      result = result.filter(
        (doctor) =>
          doctor.name.toLowerCase().includes(query) ||
          doctor.specialty.toLowerCase().includes(query) ||
          doctor.hospital.toLowerCase().includes(query)
      )
    }

    // Filter by specialty
    if (selectedSpecialty && selectedSpecialty !== 'all') {
      result = result.filter(
        (doctor) => doctor.specialtySlug === selectedSpecialty
      )
    }

    // Sort
    switch (sortBy) {
      case 'rating':
        result.sort((a, b) => b.rating - a.rating)
        break
      case 'experience':
        result.sort((a, b) => b.experience - a.experience)
        break
      case 'price-low':
        result.sort((a, b) => a.consultationFee - b.consultationFee)
        break
      case 'price-high':
        result.sort((a, b) => b.consultationFee - a.consultationFee)
        break
      default:
        // Keep default order
        break
    }

    return result
  }, [searchQuery, selectedSpecialty, sortBy])

  return (
    <div className="bg-secondary/30 min-h-screen">
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-foreground mb-2">
            Tìm bác sĩ
          </h1>
          <p className="text-muted-foreground">
            Tìm và đặt lịch khám với các bác sĩ chuyên khoa hàng đầu
          </p>
        </div>

        {/* Filters */}
        <DoctorFilter
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          selectedSpecialty={selectedSpecialty}
          onSpecialtyChange={setSelectedSpecialty}
          sortBy={sortBy}
          onSortChange={setSortBy}
        />

        {/* Results count */}
        <div className="mb-6">
          <p className="text-sm text-muted-foreground">
            Tìm thấy <span className="font-medium text-foreground">{filteredDoctors.length}</span> bác sĩ
          </p>
        </div>

        {/* Doctor Grid */}
        {filteredDoctors.length > 0 ? (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredDoctors.map((doctor) => (
              <DoctorCard key={doctor.id} doctor={doctor} />
            ))}
          </div>
        ) : (
          <div className="text-center py-16">
            <div className="w-20 h-20 bg-muted rounded-full mx-auto mb-4 flex items-center justify-center">
              <svg
                className="w-10 h-10 text-muted-foreground"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1.5}
                  d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                />
              </svg>
            </div>
            <h3 className="text-lg font-medium text-foreground mb-2">
              Không tìm thấy bác sĩ
            </h3>
            <p className="text-muted-foreground">
              Thử thay đổi bộ lọc hoặc từ khóa tìm kiếm
            </p>
          </div>
        )}
      </div>
    </div>
  )
}
